import{_ as t,o,c as a,h as n}from"./chunks/framework.Bt9YOM9y.js";const p=JSON.parse('{"title":"Getting Started for Designers","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/designers.md","filePath":"getting-started/designers.md"}'),s={name:"getting-started/designers.md"};function i(r,e,l,c,d,h){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="getting-started-for-designers" tabindex="-1">Getting Started for Designers <a class="header-anchor" href="#getting-started-for-designers" aria-label="Permalink to &quot;Getting Started for Designers&quot;">​</a></h1><p>This guide walks you through setting up the Cobalt Figma library, working with design tokens, and handing off your designs to engineering.</p><h2 id="setting-up-figma" tabindex="-1">Setting Up Figma <a class="header-anchor" href="#setting-up-figma" aria-label="Permalink to &quot;Setting Up Figma&quot;">​</a></h2><h3 id="_1-enable-the-cobalt-library" tabindex="-1">1. Enable the Cobalt Library <a class="header-anchor" href="#_1-enable-the-cobalt-library" aria-label="Permalink to &quot;1. Enable the Cobalt Library&quot;">​</a></h3><p>Open any Figma file, then go to <strong>Assets &gt; Team Library</strong> and enable the following libraries:</p><ul><li><strong>Cobalt Components</strong> — all production-ready UI components</li><li><strong>Cobalt Icons</strong> — the full icon set</li><li><strong>Cobalt Tokens</strong> — color, spacing, and typography styles</li></ul><blockquote><p><strong>Tip:</strong> Pin the Cobalt libraries to keep them at the top of your asset panel. This makes drag-and-drop much faster during daily work.</p></blockquote><h3 id="_2-install-the-cobalt-figma-plugin" tabindex="-1">2. Install the Cobalt Figma Plugin <a class="header-anchor" href="#_2-install-the-cobalt-figma-plugin" aria-label="Permalink to &quot;2. Install the Cobalt Figma Plugin&quot;">​</a></h3><p>The Cobalt plugin helps you inspect token values, check contrast ratios, and sync with the latest token updates.</p><ol><li>Open <strong>Plugins &gt; Browse plugins</strong> in Figma.</li><li>Search for &quot;Cobalt Design System.&quot;</li><li>Click <strong>Install</strong>.</li></ol><h2 id="working-with-tokens" tabindex="-1">Working with Tokens <a class="header-anchor" href="#working-with-tokens" aria-label="Permalink to &quot;Working with Tokens&quot;">​</a></h2><p>Design tokens are the single source of truth for visual style. Every color, spacing value, and font size in Cobalt maps to a named token.</p><h3 id="token-naming-convention" tabindex="-1">Token Naming Convention <a class="header-anchor" href="#token-naming-convention" aria-label="Permalink to &quot;Token Naming Convention&quot;">​</a></h3><p>Figma should mirror the same token categories used in code. In code, tokens are exposed as <code>--co-*</code> CSS variables; in Figma, the library should preserve the same category and role structure so handoff stays unambiguous.</p><p>Examples:</p><table tabindex="0"><thead><tr><th>Token Name</th><th>Value</th><th>Usage</th></tr></thead><tbody><tr><td><code>--co-color-primary-base</code></td><td><code>#154bcc</code></td><td>Primary actions, key links</td></tr><tr><td><code>--co-color-surface-raised</code></td><td><code>#fcfcfc</code></td><td>Raised surfaces and subtle cards</td></tr><tr><td><code>--co-space-inset-md</code></td><td><code>16px</code></td><td>Default component padding</td></tr><tr><td><code>--co-font-size-lg</code></td><td><code>1.125rem</code></td><td>Subheadings and emphasized labels</td></tr><tr><td><code>--co-component-avatar-size-md</code></td><td><code>32px</code></td><td>Default avatar size</td></tr></tbody></table><h3 id="applying-tokens-in-figma" tabindex="-1">Applying Tokens in Figma <a class="header-anchor" href="#applying-tokens-in-figma" aria-label="Permalink to &quot;Applying Tokens in Figma&quot;">​</a></h3><p>Always use tokens instead of raw hex values or pixel sizes. When you apply a fill, stroke, or text style:</p><ol><li>Select the layer.</li><li>Open the <strong>Design</strong> panel on the right.</li><li>Click the style swatch (color dot or text style name).</li><li>Search for the token by name — e.g., &quot;primary/base.&quot;</li><li>Select the matching style.</li></ol><blockquote><p><strong>Warning:</strong> Hardcoding values instead of using tokens causes inconsistencies and makes future theme changes painful. If a token does not exist for your use case, reach out in <code>#cobalt-support</code> before inventing one.</p></blockquote><h2 id="component-usage" tabindex="-1">Component Usage <a class="header-anchor" href="#component-usage" aria-label="Permalink to &quot;Component Usage&quot;">​</a></h2><p>Cobalt components in Figma are built with <strong>auto layout</strong>, <strong>variants</strong>, and <strong>component properties</strong> so they mirror the real implementation.</p><h3 id="key-properties" tabindex="-1">Key Properties <a class="header-anchor" href="#key-properties" aria-label="Permalink to &quot;Key Properties&quot;">​</a></h3><p>Most components expose the following properties in the right panel:</p><ul><li><strong>Size</strong> — <code>sm</code>, <code>md</code>, <code>lg</code></li><li><strong>Variant</strong> — <code>primary</code>, <code>secondary</code>, <code>ghost</code>, <code>danger</code></li><li><strong>State</strong> — <code>default</code>, <code>hover</code>, <code>focus</code>, <code>disabled</code></li><li><strong>Show Icon</strong> — toggle leading/trailing icon slots</li></ul><p>Swap icon instances by selecting the icon layer and choosing a replacement from the Cobalt Icons library.</p><h2 id="handoff-process" tabindex="-1">Handoff Process <a class="header-anchor" href="#handoff-process" aria-label="Permalink to &quot;Handoff Process&quot;">​</a></h2><p>Good handoff reduces back-and-forth and speeds up implementation. Follow these steps:</p><h3 id="_1-annotate-with-token-names" tabindex="-1">1. Annotate with Token Names <a class="header-anchor" href="#_1-annotate-with-token-names" aria-label="Permalink to &quot;1. Annotate with Token Names&quot;">​</a></h3><p>Use the Cobalt plugin&#39;s <strong>Redline</strong> mode to auto-annotate spacing, color, and typography tokens on your frames.</p><h3 id="_2-document-interaction-behavior" tabindex="-1">2. Document Interaction Behavior <a class="header-anchor" href="#_2-document-interaction-behavior" aria-label="Permalink to &quot;2. Document Interaction Behavior&quot;">​</a></h3><p>Add notes for states and transitions that are not obvious from static frames:</p><ul><li>What happens on hover, focus, and active states?</li><li>Are there loading or skeleton states?</li><li>What is the error state content?</li></ul><h3 id="_3-link-to-the-component-docs" tabindex="-1">3. Link to the Component Docs <a class="header-anchor" href="#_3-link-to-the-component-docs" aria-label="Permalink to &quot;3. Link to the Component Docs&quot;">​</a></h3><p>In your handoff notes, include links to the relevant Cobalt documentation pages so engineers can reference the API and usage examples.</p><h3 id="_4-use-the-handoff-checklist" tabindex="-1">4. Use the Handoff Checklist <a class="header-anchor" href="#_4-use-the-handoff-checklist" aria-label="Permalink to &quot;4. Use the Handoff Checklist&quot;">​</a></h3><p>Before marking a design as ready:</p><ul class="contains-task-list"><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> All colors reference Cobalt token styles</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> All text uses Cobalt type styles</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Spacing is consistent with Cobalt spacing tokens</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Components use the latest Cobalt library version</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Responsive behavior is documented for mobile, tablet, and desktop</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Accessibility annotations are present (labels, roles, focus order)</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong>Figma Library:</strong> search &quot;Cobalt&quot; in Team Libraries</li><li><strong>Token Structure:</strong> <a href="./../tokens/structure.html">How tokens are organized</a></li><li><strong>Figma Handoff:</strong> <a href="./../tokens/figma-handoff.html">What to hand off with tokens</a></li><li><strong>Figma Checklist:</strong> <a href="./../tokens/figma-checklist.html">Copy-paste handoff template</a></li><li><strong>Token Reference:</strong> <a href="./../tokens/">Tokens Documentation</a></li><li><strong>Custom Icons:</strong> Need to design a custom icon for Cobalt? See the <a href="/cobalt-design-system/foundations/iconography.html#designing-custom-icons">Designing Custom Icons</a> guide for grid specs, keyline templates, and an export checklist.</li><li><strong>Slack:</strong> <code>#cobalt-design</code></li></ul>',40)])])}const u=t(s,[["render",i]]);export{p as __pageData,u as default};
